import{a8 as t,L as s,Z as o,aK as n}from"./chunks/framework.BnqUBHC7.js";const m=JSON.parse('{"title":"Undesigned Components","description":"","frontmatter":{},"headers":[],"relativePath":"guide/undesigned-components.md","filePath":"guide/undesigned-components.md","lastUpdated":1782473967000}'),a={name:"guide/undesigned-components.md"};function i(r,e,l,h,d,c){return s(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="undesigned-components" tabindex="-1">Undesigned Components <a class="header-anchor" href="#undesigned-components" aria-label="Permalink to &quot;Undesigned Components&quot;">​</a></h1><p>vuecs components ship <strong>undesigned</strong>. Out of the box, a <code>&lt;VCButton&gt;</code> or <code>&lt;VCTable&gt;</code> brings structure (the DOM shape), behavior (state, keyboard handling), and accessibility (ARIA wiring, focus management) — but <strong>no design opinion</strong>. The only CSS a component carries is a minimal structural layer (<code>vc-*</code> classes: layout, sizing mechanics) that any look requires.</p><p>The design comes from a <strong>theme</strong>: pure data that maps each component&#39;s named slots to CSS class strings. A layered resolution engine merges the two at runtime.</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">app.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">use</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(vuecs, { themes: [</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tailwind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()] });   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// components render Tailwind utilities</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">app.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">use</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(vuecs, { themes: [</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bootstrap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()] });  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// same components, now .btn / .card / .form-control</span></span></code></pre></div><p>This page explains why that split exists, who it serves, and what it implies for how you work with vuecs.</p><h2 id="why-split-structure-from-design" tabindex="-1">Why split structure from design? <a class="header-anchor" href="#why-split-structure-from-design" aria-label="Permalink to &quot;Why split structure from design?&quot;">​</a></h2><p>Most component libraries bake a design system into the component. The class strings live inside the render function; restyling means prop-based escape hatches, CSS overrides with specificity fights, or forking.</p><p>vuecs treats the class strings as <strong>configuration, not implementation</strong>. Every component resolves its classes through the <a href="/guide/theme-system">four-layer theme chain</a> (defaults → themes → overrides → instance props) at render time. Consequences:</p><ul><li><strong>A theme is data.</strong> A function returning <code>{ elements: { button: { classes: ... } } }</code>. It can be published, composed via <a href="/guide/composing-themes"><code>defineTheme()</code></a>, stacked with other themes, and swapped at runtime.</li><li><strong>The component never knows which design system it&#39;s wearing.</strong> The Bootstrap theme emits Bootstrap&#39;s <em>native</em> classes (<code>.btn</code>, <code>.card</code>, <code>.modal-content</code>), so vuecs components sit seamlessly next to hand-written Bootstrap markup. Same for Bulma. The Tailwind theme emits utilities resolved through <a href="/guide/design-tokens">design tokens</a>.</li><li><strong>Restyling is never a fork.</strong> Override one slot of one component (<code>overrides</code>), one instance (<code>themeClass</code>), or the whole app (swap the theme) — the component code is untouched in every case.</li></ul><h2 id="who-this-is-for" tabindex="-1">Who this is for <a class="header-anchor" href="#who-this-is-for" aria-label="Permalink to &quot;Who this is for&quot;">​</a></h2><p><strong>Apps on Bootstrap or Bulma that want modern components.</strong> Most current Vue component libraries assume Tailwind or ship their own design system. With vuecs you get accessible modals, sortable tables, comboboxes and more — and the matching theme supplies your framework&#39;s native classes, so there are no visual seams and no second design system in the bundle.</p><p><strong>Apps migrating between design systems.</strong> Because design lives in a config layer, moving from Bootstrap to Tailwind (or re-branding) is a theme swap plus token adjustments — not a touch-every-call-site rewrite. Both themes can even be installed during the transition.</p><p><strong>Component-library authors.</strong> This is the deepest consequence, covered in the next section.</p><p><strong>White-label and multi-tenant apps.</strong> Palette, color mode, and theme are runtime state. Per-customer branding is a config object — <a href="/guide/design-tokens"><code>useColorPalette().set({ primary: &#39;emerald&#39; })</code></a> — not a build per tenant.</p><p>If none of these apply — you&#39;re greenfield, all-in on Tailwind, and never publishing components — a Tailwind-native kit serves you just as well. vuecs exists for when the CSS framework is a constraint you don&#39;t control.</p><h2 id="the-library-author-contract" tabindex="-1">The library-author contract <a class="header-anchor" href="#the-library-author-contract" aria-label="Permalink to &quot;The library-author contract&quot;">​</a></h2><p>The theme system is <strong>public API, not internal plumbing</strong>. Anything <code>@vuecs/*</code> components do, your components can do:</p><ol><li><strong>Declare a typed slot map</strong> on <code>ThemeElements</code> via declaration merging — your component name appears in theme autocomplete next to vuecs&#39;s built-ins.</li><li><strong>Resolve classes</strong> through <code>useComponentTheme()</code> (plus the <code>themableProps</code> / <code>useThemeProps</code> helpers), exposing the same <code>themeClass</code> / <code>themeVariant</code> props every vuecs component has.</li><li><strong>Ship your default styling</strong> as a theme — either component-local defaults, or a published theme built on an existing one via <code>defineTheme({ extends: tailwindTheme(), ... })</code>.</li></ol><p>The payoff for your consumers: <strong>one config reskins the union</strong> — vuecs primitives, your library, and any other library on the contract — through the same <code>app.use(vuecs, { themes, overrides })</code> call. You ship components <em>with</em> a designed default look, but without dictating a CSS framework: a Bootstrap shop restyles your library to Bootstrap the same way they&#39;d restyle a <code>&lt;VCButton&gt;</code>.</p><p>No registration, no plugin coupling, no parallel theme system to document. The full worked example lives at <a href="/guide/build-themable-component">Build Your Own Themable Component</a>.</p><h2 id="what-undesigned-does-not-mean" tabindex="-1">What &quot;undesigned&quot; does NOT mean <a class="header-anchor" href="#what-undesigned-does-not-mean" aria-label="Permalink to &quot;What &quot;undesigned&quot; does NOT mean&quot;">​</a></h2><ul><li><strong>Not unstyled-and-broken without a theme.</strong> The structural <code>vc-*</code> CSS keeps components functional and laid out; packages like <code>@vuecs/placeholder</code> are fully usable with zero theme installed. A theme adds the visual identity.</li><li><strong>Not headless.</strong> Headless libraries (Reka UI, Headless UI) give you behavior and <em>no markup contract</em> — you write the rendering. vuecs components render complete, opinionated DOM with named theme slots. (Internally, vuecs builds on <a href="https://reka-ui.com" target="_blank" rel="noreferrer">Reka UI</a> primitives for the accessibility heavy lifting — that layer stays an implementation detail.)</li><li><strong>Not class-string templating only.</strong> Themes also carry <a href="/guide/variants">variant definitions</a> (<code>variant</code> × <code>color</code> × <code>size</code>, compound variants), runtime hooks for color-mode and palette rendering, and merge functions — a theme is the full design half of a component, not a stylesheet.</li></ul><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="/guide/theme-system">Theme System</a> — the resolution chain that makes the split work.</li><li><a href="/guide/build-themable-component">Build Your Own Themable Component</a> — the worked library-author example.</li><li><a href="/guide/composing-themes">Composing Themes</a> — publish a theme that extends a shipped one.</li><li><a href="/guide/bridging-css-frameworks">Bridging CSS Frameworks</a> — make runtime palette switching reach a framework&#39;s native widgets.</li></ul>`,24)])])}const u=t(a,[["render",i]]);export{m as __pageData,u as default};
